// VIO83 Runtime Autopilot 360 — Analisi e decisioni automatiche
const items = $input.all();
const health = items[0]?.json || {};
const core = items[1]?.json || {};
const profile = items[2]?.json || {};

const now = new Date().toISOString();
const actions = [];
const diagnostics = [];

// 1. Backend online?
if (health.status !== 'ok') {
  actions.push('restart-backend');
  diagnostics.push('Backend non risponde o status != ok');
}

// 2. Ollama raggiungibile?
const ollamaOk = health.providers?.ollama?.available === true;
if (!ollamaOk) {
  actions.push('restart-ollama');
  diagnostics.push('Ollama non raggiungibile');
}

// 3. Modelli installati?
const modelCount = health.providers?.ollama?.models?.length || 0;
if (modelCount === 0) {
  diagnostics.push('Nessun modello Ollama installato');
}

// 4. Errori core elevati?
const errorCount = core.errors?.total_tracked || 0;
if (errorCount > 50) {
  actions.push('clear-error-log');
  diagnostics.push(`Errori accumulati: ${errorCount}`);
}

// 5. Cache cleanup necessario?
const cacheSize = core.cache?.size || 0;
if (cacheSize > 500) {
  actions.push('cache-cleanup');
  diagnostics.push(`Cache items: ${cacheSize}`);
}

// 6. Profilo corretto?
const effectiveMode = profile.effective_mode || 'unknown';
const noHybrid = profile.no_hybrid;

// 7. Uptime check
const uptimeSec = health.uptime_seconds || 0;

const score = [
  health.status === 'ok' ? 25 : 0,
  ollamaOk ? 25 : 0,
  modelCount >= 3 ? 15 : modelCount >= 1 ? 8 : 0,
  errorCount < 20 ? 15 : errorCount < 50 ? 8 : 0,
  cacheSize < 300 ? 10 : 5,
  uptimeSec > 60 ? 10 : 3,
].reduce((a, b) => a + b, 0);

return [{
  json: {
    timestamp: now,
    health_score: score,
    effective_mode: effectiveMode,
    no_hybrid: noHybrid,
    ollama_available: ollamaOk,
    model_count: modelCount,
    uptime_seconds: uptimeSec,
    error_count: errorCount,
    cache_size: cacheSize,
    actions_needed: actions,
    diagnostics: diagnostics,
    needs_action: actions.length > 0,
  }
}];

// Esegui azioni di remediation
const data = $input.first().json;
const actions = data.actions_needed || [];
const results = [];

for (const action of actions) {
  switch (action) {
    case 'cache-cleanup':
      try {
        const resp = await fetch('http://127.0.0.1:4000/core/cache/cleanup', { method: 'POST', signal: AbortSignal.timeout(5000) });
        results.push({ action, status: resp.ok ? 'done' : 'failed', code: resp.status });
      } catch (e) {
        results.push({ action, status: 'error', message: e.message });
      }
      break;
    case 'restart-ollama':
      results.push({ action, status: 'flagged', note: 'Ollama restart richiede intervento shell (launchd gestisce auto-restart)' });
      break;
    case 'restart-backend':
      results.push({ action, status: 'flagged', note: 'Backend restart gestito da PM2/launchd supervisor' });
      break;
    case 'clear-error-log':
      results.push({ action, status: 'info', note: 'Error log sarà pulito alla prossima manutenzione schedulata' });
      break;
    default:
      results.push({ action, status: 'unknown' });
  }
}

return [{ json: { ...data, remediation_results: results, remediated_at: new Date().toISOString() } }];

